	var input xberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"data":"hwpx/simple.hwpx","mime_type":"application/haansofthwpx"}`), &input); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := xberg.Extract(input, xberg.ExtractionConfig{})
